from pydantic import ValidationError
from datetime import datetime, timezone


class MessageValidationError(Exception):
    def __init__(self, code: str, detail: str):
        self.code = code
        self.detail = detail
        super().__init__(detail)


def validate_inbound(raw: str, my_agent_id: str) -> StructuredMessage:
    """Parse, schema-check, and business-check an inbound message."""
    # Stage 1: JSON parse + schema validation
    try:
        msg = StructuredMessage.from_json(raw)
    except ValidationError as exc:
        raise MessageValidationError("SCHEMA_ERROR", str(exc))

    # Stage 2: routing check — is this actually addressed to me?
    if msg.header.receiver != my_agent_id:
        raise MessageValidationError(
            "WRONG_RECEIVER",
            f"Message addressed to {msg.header.receiver!r}, not {my_agent_id!r}",
        )

    # Stage 3: TTL check — has the message expired in transit?
    age = (datetime.now(timezone.utc) - msg.header.timestamp).total_seconds()
    if age > msg.metadata.ttl_seconds:
        raise MessageValidationError(
            "MESSAGE_EXPIRED",
            f"Message is {age:.0f}s old; TTL is {msg.metadata.ttl_seconds}s",
        )

    return msg


def safe_handle(raw: str, my_id: str, reply_fn) -> StructuredMessage | None:
    """Validate and handle; send FAILURE reply on error."""
    try:
        return validate_inbound(raw, my_id)
    except MessageValidationError as exc:
        failure = StructuredMessage(
            header=MessageHeader(sender=my_id, receiver="unknown"),
            intent=MessageIntent(performative="FAILURE"),
            payload={"error_code": exc.code, "detail": exc.detail},
        )
        reply_fn(failure)
        return None

import logging
from opentelemetry import trace

logger = logging.getLogger(__name__)
tracer = trace.get_tracer("agent.messaging")


def send_with_tracing(msg: StructuredMessage, bus) -> StructuredMessage:
    """Inject the current OTel trace ID into the message before sending."""
    span = trace.get_current_span()
    ctx = span.get_span_context()
    if ctx.is_valid:
        trace_id = format(ctx.trace_id, "032x")
        msg = msg.model_copy(
            update={"metadata": msg.metadata.model_copy(update={"trace_id": trace_id})}
        )

    with tracer.start_as_current_span(
        f"send/{msg.intent.performative}",
        attributes={
            "msg.id": msg.header.msg_id,
            "msg.sender": msg.header.sender,
            "msg.receiver": msg.header.receiver,
        },
    ):
        bus.publish(msg)
        logger.info(
            "message sent",
            extra={
                "msg_id": msg.header.msg_id,
                "performative": msg.intent.performative,
                "trace_id": msg.metadata.trace_id,
            },
        )
    return msg
